VALUES
  ('medio', '1', 1, 13, 'Filosofia',
   'A arte em diálogo com o mundo contemporâneo', '• A produção de significados e a reflexão estética.', '• Analisar significados produzidos por manifestações artísticas contemporâneas de diferentes linguagens.',
   NULL, 'EM13CHS104',
